import hmac
import hashlib
import time
from typing import Any

# 模拟数据库存储（生产环境请替换为真实数据库）
_webhook_store: list[dict[str, Any]] = []


def handle_webhook(
    payload: dict[str, Any],
    signature: str,
    secret: str = "your-webhook-secret",
    timestamp: str | None = None,
) -> dict[str, Any]:
    """
    处理外部 webhook POST 请求。

    参数:
        payload:  请求体中的 JSON 数据 (dict)
        signature: 请求头中的签名 (如 X-Signature)
        secret:    用于验证签名的密钥（建议通过环境变量传入）
        timestamp: 请求头中的时间戳 (可选，用于防重放攻击)

    返回:
        {"success": True, "stored_id": "uuid"}
        或 {"success": False, "error": "签名验证失败"}

    签名算法: HMAC-SHA256(payload_json + timestamp, secret)
    """
    # 1. 构造待签名字符串
    payload_str = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    sign_base = payload_str
    if timestamp:
        sign_base = payload_str + timestamp

    # 2. 验证签名
    expected_sig = hmac.new(
        secret.encode("utf-8"),
        sign_base.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    if not hmac.compare_digest(expected_sig, signature):
        return {"success": False, "error": "签名验证失败"}

    # 3. (可选) 时间戳防重放检查：5 分钟内有效
    if timestamp:
        try:
            ts = int(timestamp)
            now = int(time.time())
            if abs(now - ts) > 300:
                return {"success": False, "error": "请求已过期"}
        except ValueError:
            return {"success": False, "error": "时间戳格式错误"}

    # 4. 落库
    record = {
        "id": f"wh_{int(time.time() * 1_000_000)}",
        "payload": payload,
        "received_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
        "verified": True,
    }
    _webhook_store.append(record)

    return {"success": True, "stored_id": record["id"]}


def get_stored_webhooks(limit: int = 10) -> list[dict[str, Any]]:
    """辅助函数：查看已存储的 webhook 记录（调试用）"""
    return _webhook_store[-limit:]
