{"name": "process_webhook", "kind": "normal", "description": "处理外部webhook的POST请求，验证HMAC签名后将数据落库存储", "code": "import hmac
import hashlib
import json
import time
from datetime import datetime

# 共享密钥（生产环境应从环境变量或密钥管理服务获取）
WEBHOOK_SECRET = "your-webhook-secret-key"

def process_webhook(payload: dict, signature: str, timestamp: str = None) -> dict:
    """
    处理外部 webhook POST 请求。

    参数:
        payload:   请求体 JSON 解析后的字典
        signature: 请求头中携带的签名 (例如 X-Signature)
        timestamp: 请求时间戳（可选，用于防重放攻击）

    返回:
        {"success": True, "record_id": "xxx", "message": "处理成功"}
        或 {"success": False, "message": "签名验证失败"}
    """
    # 1. 防重放攻击：检查时间戳是否在合理范围内（5分钟）
    if timestamp:
        try:
            req_time = int(timestamp)
            now = int(time.time())
            if abs(now - req_time) > 300:
                return {"success": False, "message": "请求已过期，拒绝处理"}
        except ValueError:
            return {"success": False, "message": "时间戳格式无效"}

    # 2. 验证签名
    # 构造签名源串：通常按 JSON 序列化 payload（key 排序）+ 时间戳
    sorted_payload = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    raw_string = sorted_payload
    if timestamp:
        raw_string = timestamp + "." + sorted_payload

    expected_sig = hmac.new(
        WEBHOOK_SECRET.encode("utf-8"),
        raw_string.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    if not hmac.compare_digest(expected_sig, signature):
        return {"success": False, "message": "签名验证失败"}

    # 3. 签名通过，落库存储
    record = {
        "event_type": payload.get("event", "unknown"),
        "data": payload.get("data", payload),
        "received_at": datetime.utcnow().isoformat() + "Z",
        "signature": signature,
    }

    # 实际生产环境中替换为数据库插入逻辑，例如：
    # record_id = db.table("webhook_events").insert(record).execute()
    # 这里用内存模拟
    record_id = hashlib.md5(
        json.dumps(record, sort_keys=True).encode()
    ).hexdigest()[:12]

    return {
        "success": True,
        "record_id": record_id,
        "message": "Webhook 处理成功",
        "record": record,
    }"}
